function solve(nums: number[], k: number): number {
    nums.sort((a, b) => a - b);
    let max_size = 1;
    for (let i = 0; i < nums.length; i++) {
        const target = nums[i] * k;
        let left = i;
        let right = nums.length - 1;
        let j = -1;
        while (left <= right) {
            const mid = Math.floor((left + right) / 2);
            if (nums[mid] <= target) {
                j = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        if (j !== -1) {
            const current_size = j - i + 1;
            if (current_size > max_size) {
                max_size = current_size;
            }
        }
    }
    return nums.length - max_size;
}

